import{_ as t,a,b as r,c as i,d as n}from"./chunks/fig9.Oq9aRFns.js";import{_ as o,c as s,o as l,ae as c}from"./chunks/framework.Bzon8x8e.js";const S=JSON.parse('{"title":"Deep Transfer Learning (SDTL) for Cross-Scenario SOH Estimation of Lithium-Ion Batteries","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),d={name:"index.md"};function h(g,e,m,p,f,u){return l(),s("div",null,[...e[0]||(e[0]=[c('<h1 id="deep-transfer-learning-sdtl-for-cross-scenario-soh-estimation-of-lithium-ion-batteries" tabindex="-1">Deep Transfer Learning (SDTL) for Cross-Scenario SOH Estimation of Lithium-Ion Batteries <a class="header-anchor" href="#deep-transfer-learning-sdtl-for-cross-scenario-soh-estimation-of-lithium-ion-batteries" aria-label="Permalink to &quot;Deep Transfer Learning (SDTL) for Cross-Scenario SOH Estimation of Lithium-Ion Batteries&quot;">​</a></h1><h2 id="i-introduction" tabindex="-1">I. Introduction <a class="header-anchor" href="#i-introduction" aria-label="Permalink to &quot;I. Introduction&quot;">​</a></h2><p>With the explosive growth of electric vehicles and energy storage systems, accurate estimation of the <strong>State of Health (SOH)</strong> of lithium-ion batteries is crucial for ensuring system safety and extending battery lifespan.</p><p>However, in practical applications, we face two major challenges:</p><ul><li><strong>Complex and Variable Environment</strong>: Different cathode materials (such as NCM, NCA), dramatic fluctuations in ambient temperature, and diverse charge-discharge protocols.</li><li><strong>Data Silos and Sample Scarcity</strong>: New batteries have extremely limited data during their early service period, while traditional deep learning models often require massive labeled data to achieve good generalization ability.</li></ul><p>To address these challenges, a paper published in the prestigious journal <em>Journal of Power Sources</em> titled <em><strong>Deep transfer learning enabled online state-of-health estimation of lithium-ion batteries under small samples across different cathode materials</strong></em> presents the latest research findings: a <strong>Deep Transfer Learning (SDTL)</strong> method based on a <strong>Self-Attention Mechanism</strong>.</p><h2 id="ii-sdtl-framework" tabindex="-1">II. SDTL Framework <a class="header-anchor" href="#ii-sdtl-framework" aria-label="Permalink to &quot;II. SDTL Framework&quot;">​</a></h2><p>The study proposes an efficient SDTL system with three core components: <strong>feature extraction</strong>, <strong>pre-training</strong>, and <strong>fine-tuning</strong>:</p><p align="center"><img src="'+t+'" style="width:100%;margin:0 auto;display:block;"></p><p align="center" style="color:grey;">System Architecture of Deep Transfer Learning (SDTL) Based on Self-Attention Mechanism</p><h3 id="_1-multi-source-health-indicator-hi-extraction" tabindex="-1">1. Multi-Source Health Indicator (HI) Extraction <a class="header-anchor" href="#_1-multi-source-health-indicator-hi-extraction" aria-label="Permalink to &quot;1. Multi-Source Health Indicator (HI) Extraction&quot;">​</a></h3><p>The researchers extracted <strong>18 health indicators</strong> from charge voltage/current, discharge voltage/current, and incremental capacity (IC) curves. By using <strong>Pearson Correlation Coefficient (PCC)</strong> to filter out features highly correlated with SOH (such as HI3, HI5, HI11, etc.), they ensured the physical interpretability and representation capability of the input data.</p><p align="center"><img src="'+a+'" style="width:100%;margin:0 auto;display:block;"></p><p align="center" style="color:grey;">Pearson Correlation Coefficient (PCC) Analysis Between Extracted Health Indicators (HIs) and SOH</p><h3 id="_2-self-attention-mechanism" tabindex="-1">2. Self-Attention Mechanism <a class="header-anchor" href="#_2-self-attention-mechanism" aria-label="Permalink to &quot;2. Self-Attention Mechanism&quot;">​</a></h3><p>Unlike traditional RNN or LSTM, SDTL employs a <strong>Multi-Head Self-Attention Mechanism</strong>. It captures global dependencies at different positions in time series and automatically assigns weights to more critical degradation features, enabling more accurate identification of battery degradation patterns under different operating conditions.</p><p align="center"><img src="'+r+'" style="width:100%;margin:0 auto;display:block;"></p><p align="center" style="color:grey;">Multi-Head Self-Attention Module Architecture Diagram</p><h3 id="_3-deep-transfer-learning" tabindex="-1">3. Deep Transfer Learning <a class="header-anchor" href="#_3-deep-transfer-learning" aria-label="Permalink to &quot;3. Deep Transfer Learning&quot;">​</a></h3><ul><li><strong>Pre-training (Offline)</strong>: Utilizing large amounts of historical battery data (source domain) for pre-training, enabling the model to learn general battery degradation patterns.</li><li><strong>Fine-tuning (Online)</strong>: For new battery tasks (target domain), only the first 10% of early-cycle data is required to complete online adaptation. By freezing the lower-layer feature extraction layers and updating only the output layer parameters, fast and cost-effective cross-scenario transfer is achieved.</li></ul><h2 id="iii-experimental-validation" tabindex="-1">III. Experimental Validation <a class="header-anchor" href="#iii-experimental-validation" aria-label="Permalink to &quot;III. Experimental Validation&quot;">​</a></h2><p>To verify the generalization performance of SDTL, the researchers conducted extremely rigorous experimental tests:</p><p align="center"><img src="'+i+'" style="width:100%;margin:0 auto;display:block;"></p><p align="center" style="color:grey;">SOH Estimation Results of SDTL Model on Experimental Battery Data</p><ul><li><strong>Comprehensive Dataset Coverage</strong>: Includes self-built NCM battery datasets (1C/2C rates) and publicly available NASA NCA battery datasets (covering 24°C and 4°C ambient temperatures).</li><li><strong>Performance Results</strong>: Experimental results show that even under challenging conditions such as low temperature (4°C) and high discharge rates, SDTL demonstrates extremely high estimation accuracy and robustness.</li><li><strong>Comparative Advantages</strong>: Compared to mainstream deep learning algorithms and other transfer learning methods, SDTL exhibits clear advantages in small-sample scenarios, eliminating the high cost of training models from scratch.</li></ul><p align="center"><img src="'+n+'" style="width:100%;margin:0 auto;display:block;"></p><p align="center" style="color:grey;">Comparison of Prediction Performance Between SDTL and Mainstream Models (CNN-LSTM, GRU, ResNet)</p><h2 id="iv-conclusion" tabindex="-1">IV. Conclusion <a class="header-anchor" href="#iv-conclusion" aria-label="Permalink to &quot;IV. Conclusion&quot;">​</a></h2><p>The paper&#39;s contributions are primarily reflected in:</p><ul><li><strong>Efficiency</strong>: Quick online adaptation can be achieved with only 10% of the data.</li><li><strong>Broad Applicability</strong>: Can handle different cathode materials (NCM vs NCA) and environmental temperature variations.</li><li><strong>Engineering Value</strong>: Provides a practical, lightweight, and high-precision SOH online estimation solution for BMS (Battery Management Systems).</li></ul><hr><h2 id="reference-information" tabindex="-1">Reference Information <a class="header-anchor" href="#reference-information" aria-label="Permalink to &quot;Reference Information&quot;">​</a></h2><ul><li><strong>Title</strong>: Deep transfer learning enabled online state-of-health estimation of lithium-ion batteries under small samples across different cathode materials, ambient temperature and charge-discharge protocols</li><li><strong>Journal</strong>: Journal of Power Sources (2025)</li><li><strong>DOI</strong>: 10.1016/j.jpowsour.2025.237503</li><li><strong>Link</strong>: <a href="https://doi.org/10.1016/j.jpowsour.2025.237503" target="_blank" rel="noreferrer">https://doi.org/10.1016/j.jpowsour.2025.237503</a></li></ul>',33)])])}const _=o(d,[["render",h]]);export{S as __pageData,_ as default};
